contract CTCVesting is Ownable {

  using SafeMath for uint256;



  address public teamWallet;

  address public earlyWallet;

  address public institutionWallet;



  uint256 public teamTimeLock = 1000 days;

  uint256 public earlyTimeLock = 5 * 30 days;

  uint256 public institutionTimeLock = 50 * 30 days;





  uint256 public teamAllocation = 15 * (10 ** 7) * (10 ** 18);

  uint256 public earlyAllocation = 5 * (10 ** 7) * (10 ** 18);

  uint256 public institutionAllocation = 15 * (10 ** 7) * (10 ** 18);



  uint256 public totalAllocation = 35 * (10 ** 7) * (10 ** 18);



  uint256 public teamStageSetting = 34;

  uint256 public earlyStageSetting = 5;

  uint256 public institutionStageSetting = 50;

  ERC20Basic public token;



  uint256 public start;



  uint256 public lockStartTime; 



    mapping(address => uint256) public allocations;



    mapping(address => uint256) public stageSettings;



    mapping(address => uint256) public timeLockDurations;





    mapping(address => uint256) public releasedAmounts;



    modifier onlyReserveWallets {

        require(allocations[msg.sender] > 0);

        _;

    }

    function CTCVesting(ERC20Basic _token,

                          address _teamWallet,

                          address _earlyWallet,

                          address _institutionWallet,

                          uint256 _start,

                          uint256 _lockTime)public{

        require(_start > 0);

        require(_lockTime > 0);

        require(_start.add(_lockTime) > 0);

        require(_teamWallet != address(0));

        require(_earlyWallet != address(0));

        require(_institutionWallet != address(0));



        token = _token;

        teamWallet = _teamWallet;

        earlyWallet = _earlyWallet;

        institutionWallet = _institutionWallet;

        start = _start;

        lockStartTime = start.add(_lockTime);

    }



    function allocateToken() onlyOwner public{

        require(block.timestamp > lockStartTime);



        require(allocations[teamWallet] == 0);

        require(token.balanceOf(address(this)) == totalAllocation);



        allocations[teamWallet] = teamAllocation;

        allocations[earlyWallet] = earlyAllocation;

        allocations[institutionWallet] = institutionAllocation;



        stageSettings[teamWallet] = teamStageSetting;

        stageSettings[earlyWallet] = earlyStageSetting;

        stageSettings[institutionWallet] = institutionStageSetting;



        timeLockDurations[teamWallet] = teamTimeLock;

        timeLockDurations[earlyWallet] = earlyTimeLock;

        timeLockDurations[institutionWallet] = institutionTimeLock;

    }

    function releaseToken() onlyReserveWallets public{

        uint256 totalUnlocked = unlockAmount();

        require(totalUnlocked <= allocations[msg.sender]);

        require(releasedAmounts[msg.sender] < totalUnlocked);

        uint256 payment = totalUnlocked.sub(releasedAmounts[msg.sender]);



        releasedAmounts[msg.sender] = totalUnlocked;

        require(token.transfer(teamWallet, payment));

    }

    function unlockAmount() public view onlyReserveWallets returns(uint256){

        uint256 stage = vestStage();

        uint256 totalUnlocked = stage.mul(allocations[msg.sender]).div(stageSettings[msg.sender]);

        return totalUnlocked;

    }



    function vestStage() public view onlyReserveWallets returns(uint256){

        uint256 vestingMonths = timeLockDurations[msg.sender].div(stageSettings[msg.sender]);

        uint256 stage = (block.timestamp.sub(lockStartTime)).div(vestingMonths);



        if(stage > stageSettings[msg.sender]){

            stage = stageSettings[msg.sender];

        }

        return stage;

    }

}

contract XTVToken is XTVNetworkGuard, ERC20Token {

  using SafeMath for uint256;



  string public name = "XTV Network";

  string public symbol = "XTV";

  uint public decimals = 18;



  address public fullfillTeamAddress;

  address public fullfillFounder;

  address public fullfillAdvisors;

  address public XTVNetworkContractAddress;



  bool public airdropActive;

  uint public startTime;

  uint public endTime;

  uint public XTVAirDropped;

  uint public XTVBurned;

  mapping(address => bool) public claimed;



  uint256 public constant INITIAL_SUPPLY = 500000000;

  uint256 public constant EXPECTED_TOTAL_SUPPLY = 1000000000;

  uint256 private constant TOKEN_MULTIPLIER = 1000000;





  uint256 public constant ALLOC_TEAM = 330 * TOKEN_MULTIPLIER;



  uint256 public constant ALLOC_ADVISORS = 70 * TOKEN_MULTIPLIER;



  uint256 public constant ALLOC_FOUNDER = 100 * TOKEN_MULTIPLIER;



  uint256 public constant ALLOC_AIRDROP = 500 * TOKEN_MULTIPLIER;



  uint256 public constant AIRDROP_CLAIM_AMMOUNT = 500;



  modifier isAirdropActive() {

    require(airdropActive);

    _;

  }



  modifier canClaimTokens() {

    uint256 remainingSupply = balances[address(0)];



    require(!claimed[msg.sender] && remainingSupply > AIRDROP_CLAIM_AMMOUNT);

    _;

  }



  event LogAirdropClaim(

    address addr,

    string token,

    bytes32 verificationHash,

    bytes xtvSignature

  );



  constructor(

    address _fullfillTeam,

    address _fullfillFounder,

    address _fullfillAdvisors

  ) public {

    owner = msg.sender;

    fullfillTeamAddress = _fullfillTeam;

    fullfillFounder = _fullfillFounder;

    fullfillAdvisors = _fullfillAdvisors;



    airdropActive = true;

    startTime = block.timestamp;

    endTime = startTime + 365 days;



    balances[_fullfillTeam] = ALLOC_TEAM;

    balances[_fullfillFounder] = ALLOC_FOUNDER;

    balances[_fullfillAdvisors] = ALLOC_ADVISORS;



    balances[address(0)] = ALLOC_AIRDROP;



    totalSupply_ = INITIAL_SUPPLY;

  }



  function setXTVNetworkEndorser(address _addr, bool isEndorser) public onlyOwner {

    xtvNetworkEndorser[_addr] = isEndorser;

  }





  function claim(

    string memory token,

    bytes32 verificationHash,

    bytes memory xtvSignature

  ) 

    public

    isAirdropActive

    canClaimTokens

    validateSignature(token, verificationHash, xtvSignature)

    returns (uint256)

  {

    claimed[msg.sender] = true;



    balances[address(0)] = balances[address(0)].sub(AIRDROP_CLAIM_AMMOUNT);

    balances[msg.sender] = balances[msg.sender].add(AIRDROP_CLAIM_AMMOUNT);



    XTVAirDropped = XTVAirDropped.add(AIRDROP_CLAIM_AMMOUNT);

    totalSupply_ = totalSupply_.add(AIRDROP_CLAIM_AMMOUNT);



    emit LogAirdropClaim(msg.sender, token, verificationHash, xtvSignature);



    return balances[msg.sender];

  }







  function burnTokens() public {

    if (block.timestamp > endTime) {

      uint256 remaining = balances[address(0)];



      airdropActive = false;



      XTVBurned = remaining;

    }

  }



  function setXTVNetworkContractAddress(address addr) public onlyOwner {

    XTVNetworkContractAddress = addr;

  }



  function setXTVTokenAirdropStatus(bool _status) public onlyOwner {

    airdropActive = _status;

  }



  function drain() public onlyOwner {

    owner.transfer(address(this).balance);

  }

}

