    function buyCore(uint256 _pID, uint256 _affID, uint256 _team, F3Ddatasets.EventReturns memory _eventData_)

    private

    {



        uint256 _rID = rID_;





        uint256 _now = now;





        if (_now > round_[_rID].strt + rndGap_ && (_now <= round_[_rID].end || (_now > round_[_rID].end && round_[_rID].plyr == 0)))

        {



            core(_rID, _pID, msg.value, _affID, _team, _eventData_);





        } else {



            if (_now > round_[_rID].end && round_[_rID].ended == false)

            {



                round_[_rID].ended = true;

                _eventData_ = endRound(_eventData_);





                _eventData_.compressedData = _eventData_.compressedData + (_now * 1000000000000000000);

                _eventData_.compressedIDs = _eventData_.compressedIDs + _pID;





                emit F3Devents.onBuyAndDistribute

                (

                    msg.sender,

                    plyr_[_pID].name,

                    msg.value,

                    _eventData_.compressedData,

                    _eventData_.compressedIDs,

                    _eventData_.winnerAddr,

                    _eventData_.winnerName,

                    _eventData_.amountWon,

                    _eventData_.newPot,

                    _eventData_.mktAmount,

                    _eventData_.genAmount

                );

            }





            plyr_[_pID].gen = plyr_[_pID].gen.add(msg.value);

        }

    }





    function reLoadCore(uint256 _pID, uint256 _affID, uint256 _team, uint256 _eth, F3Ddatasets.EventReturns memory _eventData_)

    private

    {



        uint256 _rID = rID_;





        uint256 _now = now;





        if (_now > round_[_rID].strt + rndGap_ && (_now <= round_[_rID].end || (_now > round_[_rID].end && round_[_rID].plyr == 0)))

        {







            plyr_[_pID].gen = withdrawEarnings(_pID).sub(_eth);





            core(_rID, _pID, _eth, _affID, _team, _eventData_);





        } else if (_now > round_[_rID].end && round_[_rID].ended == false) {



            round_[_rID].ended = true;

            _eventData_ = endRound(_eventData_);





            _eventData_.compressedData = _eventData_.compressedData + (_now * 1000000000000000000);

            _eventData_.compressedIDs = _eventData_.compressedIDs + _pID;





            emit F3Devents.onReLoadAndDistribute

            (

                msg.sender,

                plyr_[_pID].name,

                _eventData_.compressedData,

                _eventData_.compressedIDs,

                _eventData_.winnerAddr,

                _eventData_.winnerName,

                _eventData_.amountWon,

                _eventData_.newPot,

                _eventData_.mktAmount,

                _eventData_.genAmount

            );

        }

    }





    function core(uint256 _rID, uint256 _pID, uint256 _eth, uint256 _affID, uint256 _team, F3Ddatasets.EventReturns memory _eventData_)

    private

    {



        if (plyrRnds_[_pID][_rID].keys == 0)

            _eventData_ = managePlayer(_pID, _eventData_);





        if (round_[_rID].eth < 100000000000000000000 && plyrRnds_[_pID][_rID].eth.add(_eth) > 1000000000000000000)

        {

            uint256 _availableLimit = (1000000000000000000).sub(plyrRnds_[_pID][_rID].eth);

            uint256 _refund = _eth.sub(_availableLimit);

            plyr_[_pID].gen = plyr_[_pID].gen.add(_refund);

            _eth = _availableLimit;

        }





        if (_eth > 1000000000)

        {



            uint256 _keys = (round_[_rID].eth).keysRec(_eth);





            if (_keys >= 1000000000000000000)

            {

                updateTimer(_keys, _rID);





                if (round_[_rID].plyr != _pID)

                    round_[_rID].plyr = _pID;

                if (round_[_rID].team != _team)

                    round_[_rID].team = _team;





                _eventData_.compressedData = _eventData_.compressedData + 100;

            }





            if (_eth >= 100000000000000000)

            {

                airDropTracker_++;

                if (airdrop() == true)

                {



                    uint256 _prize;

                    if (_eth >= 10000000000000000000)

                    {



                        _prize = ((airDropPot_).mul(75)) / 100;

                        plyr_[_pID].win = (plyr_[_pID].win).add(_prize);





                        airDropPot_ = (airDropPot_).sub(_prize);





                        _eventData_.compressedData += 300000000000000000000000000000000;

                    } else if (_eth >= 1000000000000000000 && _eth < 10000000000000000000) {



                        _prize = ((airDropPot_).mul(50)) / 100;

                        plyr_[_pID].win = (plyr_[_pID].win).add(_prize);





                        airDropPot_ = (airDropPot_).sub(_prize);





                        _eventData_.compressedData += 200000000000000000000000000000000;

                    } else if (_eth >= 100000000000000000 && _eth < 1000000000000000000) {



                        _prize = ((airDropPot_).mul(25)) / 100;

                        plyr_[_pID].win = (plyr_[_pID].win).add(_prize);





                        airDropPot_ = (airDropPot_).sub(_prize);





                        _eventData_.compressedData += 300000000000000000000000000000000;

                    }



                    _eventData_.compressedData += 10000000000000000000000000000000;



                    _eventData_.compressedData += _prize * 1000000000000000000000000000000000;





                    airDropTracker_ = 0;

                }

            }





            _eventData_.compressedData = _eventData_.compressedData + (airDropTracker_ * 1000);





            plyrRnds_[_pID][_rID].keys = _keys.add(plyrRnds_[_pID][_rID].keys);

            plyrRnds_[_pID][_rID].eth = _eth.add(plyrRnds_[_pID][_rID].eth);





            round_[_rID].keys = _keys.add(round_[_rID].keys);

            round_[_rID].eth = _eth.add(round_[_rID].eth);

            rndTmEth_[_rID][_team] = _eth.add(rndTmEth_[_rID][_team]);





            _eventData_ = distributeExternal(_rID, _pID, _eth, _affID, _team, _eventData_);

            _eventData_ = distributeInternal(_rID, _pID, _eth, _team, _keys, _eventData_);





            endTx(_pID, _team, _eth, _keys, _eventData_);

        }

    }



    function calcUnMaskedEarnings(uint256 _pID, uint256 _rIDlast)

    private

    view

    returns(uint256)

    {

        return(  (((round_[_rIDlast].mask).mul(plyrRnds_[_pID][_rIDlast].keys)) / (1000000000000000000)).sub(plyrRnds_[_pID][_rIDlast].mask)  );

    }





    function calcKeysReceived(uint256 _rID, uint256 _eth)

    public

    view

    returns(uint256)

    {



        uint256 _now = now;





        if (_now > round_[_rID].strt + rndGap_ && (_now <= round_[_rID].end || (_now > round_[_rID].end && round_[_rID].plyr == 0)))

            return ( (round_[_rID].eth).keysRec(_eth) );

        else  

            return ( (_eth).keys() );

    }





    function iWantXKeys(uint256 _keys)

    public

    view

    returns(uint256)

    {



        uint256 _rID = rID_;





        uint256 _now = now;





        if (_now > round_[_rID].strt + rndGap_ && (_now <= round_[_rID].end || (_now > round_[_rID].end && round_[_rID].plyr == 0)))

            return ( (round_[_rID].keys.add(_keys)).ethRec(_keys) );

        else  

            return ( (_keys).eth() );

    }











    function receivePlayerInfo(uint256 _pID, address _addr, bytes32 _name, uint256 _laff)

    external

    {

        require (msg.sender == address(PlayerBook), "your not playerNames contract... hmmm..");

        if (pIDxAddr_[_addr] != _pID)

            pIDxAddr_[_addr] = _pID;

        if (pIDxName_[_name] != _pID)

            pIDxName_[_name] = _pID;

        if (plyr_[_pID].addr != _addr)

            plyr_[_pID].addr = _addr;

        if (plyr_[_pID].name != _name)

            plyr_[_pID].name = _name;

        if (plyr_[_pID].laff != _laff)

            plyr_[_pID].laff = _laff;

        if (plyrNames_[_pID][_name] == false)

            plyrNames_[_pID][_name] = true;

    }





    function receivePlayerNameList(uint256 _pID, bytes32 _name)

    external

    {

        require (msg.sender == address(PlayerBook), "your not playerNames contract... hmmm..");

        if(plyrNames_[_pID][_name] == false)

            plyrNames_[_pID][_name] = true;

    }





    function determinePID(F3Ddatasets.EventReturns memory _eventData_)

    private

    returns (F3Ddatasets.EventReturns)

    {

        uint256 _pID = pIDxAddr_[msg.sender];



        if (_pID == 0)

        {



            _pID = PlayerBook.getPlayerID(msg.sender);

            bytes32 _name = PlayerBook.getPlayerName(_pID);

            uint256 _laff = PlayerBook.getPlayerLAff(_pID);





            pIDxAddr_[msg.sender] = _pID;

            plyr_[_pID].addr = msg.sender;



            if (_name != "")

            {

                pIDxName_[_name] = _pID;

                plyr_[_pID].name = _name;

                plyrNames_[_pID][_name] = true;

            }



            if (_laff != 0 && _laff != _pID)

                plyr_[_pID].laff = _laff;





            _eventData_.compressedData = _eventData_.compressedData + 1;

        }

        return (_eventData_);

    }





    function verifyTeam(uint256 _team)

    private

    pure

    returns (uint256)

    {

        if (_team < 0 || _team > 3)

            return(2);

        else

            return(_team);

    }





    function managePlayer(uint256 _pID, F3Ddatasets.EventReturns memory _eventData_)

    private

    returns (F3Ddatasets.EventReturns)

    {





        if (plyr_[_pID].lrnd != 0)

            updateGenVault(_pID, plyr_[_pID].lrnd);





        plyr_[_pID].lrnd = rID_;





        _eventData_.compressedData = _eventData_.compressedData + 10;



        return(_eventData_);

    }





    function endRound(F3Ddatasets.EventReturns memory _eventData_)

    private

    returns (F3Ddatasets.EventReturns)

    {



        uint256 _rID = rID_;





        uint256 _winPID = round_[_rID].plyr;

        uint256 _winTID = round_[_rID].team;





        uint256 _pot = round_[_rID].pot;







        uint256 _win = (_pot.mul(48)) / 100;

        uint256 _com = (_pot / 50);

        uint256 _gen = (_pot.mul(potSplit_[_winTID].gen)) / 100;

        uint256 _mkt = (_pot.mul(potSplit_[_winTID].marketing)) / 100;

        uint256 _res = ((_pot.sub(_win)).sub(_com)).sub(_gen).sub(_mkt);





        uint256 _ppt = (_gen.mul(1000000000000000000)) / (round_[_rID].keys);

        uint256 _dust = _gen.sub((_ppt.mul(round_[_rID].keys)) / 1000000000000000000);

        if (_dust > 0)

        {

            _gen = _gen.sub(_dust);

            _res = _res.add(_dust);

        }





        plyr_[_winPID].win = _win.add(plyr_[_winPID].win);





        _com = _com.add(_mkt);

        if (!owner.send(_com)) {

            _com = 0;

            _res = _res.add(_com);

        }





        round_[_rID].mask = _ppt.add(round_[_rID].mask);





        _eventData_.compressedData = _eventData_.compressedData + (round_[_rID].end * 1000000);

        _eventData_.compressedIDs = _eventData_.compressedIDs + (_winPID * 100000000000000000000000000) + (_winTID * 100000000000000000);

        _eventData_.winnerAddr = plyr_[_winPID].addr;

        _eventData_.winnerName = plyr_[_winPID].name;

        _eventData_.amountWon = _win;

        _eventData_.genAmount = _gen;

        _eventData_.mktAmount = _mkt;



        _eventData_.newPot = _res;





        rID_++;

        _rID++;

        round_[_rID].strt = now;

        round_[_rID].end = now.add(rndInit_).add(rndGap_);

        round_[_rID].pot = _res;



        return(_eventData_);

    }





    function updateGenVault(uint256 _pID, uint256 _rIDlast)

    private

    {

        uint256 _earnings = calcUnMaskedEarnings(_pID, _rIDlast);

        if (_earnings > 0)

        {



            plyr_[_pID].gen = _earnings.add(plyr_[_pID].gen);



            plyrRnds_[_pID][_rIDlast].mask = _earnings.add(plyrRnds_[_pID][_rIDlast].mask);

        }

    }





    function updateTimer(uint256 _keys, uint256 _rID)

    private

    {



        uint256 _now = now;





        uint256 _newTime;

        if (_now > round_[_rID].end && round_[_rID].plyr == 0)

            _newTime = (((_keys) / (1000000000000000000)).mul(rndInc_)).add(_now);

        else

            _newTime = (((_keys) / (1000000000000000000)).mul(rndInc_)).add(round_[_rID].end);





        if (_newTime < (rndMax_).add(_now))

            round_[_rID].end = _newTime;

        else

            round_[_rID].end = rndMax_.add(_now);

    }





    function airdrop()

    private

    view

    returns(bool)

    {

        uint256 seed = uint256(keccak256(abi.encodePacked((block.timestamp).add(block.difficulty).add((uint256(keccak256(abi.encodePacked(block.coinbase)))) / (now)).add(block.gaslimit).add((uint256(keccak256(abi.encodePacked(msg.sender)))) / (now)).add(block.number))));

        if((seed - ((seed / 1000) * 1000)) < airDropTracker_)

            return(true);

        else

            return(false);

    }





    function distributeExternal(uint256 _rID, uint256 _pID, uint256 _eth, uint256 _affID, uint256 _team, F3Ddatasets.EventReturns memory _eventData_)

    private

    returns(F3Ddatasets.EventReturns)

    {



        uint256 _com = _eth / 50;





        uint256 _aff = _eth / 10;







        if (_affID != _pID && plyr_[_affID].name != '') {

            plyr_[_affID].aff = _aff.add(plyr_[_affID].aff);

            emit F3Devents.onAffiliatePayout(_affID, plyr_[_affID].addr, plyr_[_affID].name, _rID, _pID, _aff, now);

        } else {

            _com = _com.add(_aff);

        }



        uint256 _mkt = _eth.mul(fees_[_team].marketing) / 100;

        _com = _com.add(_mkt);

        owner.transfer(_com);



        _eventData_.mktAmount = _mkt;



        return(_eventData_);

    }



    function potSwap()

    external

    payable

    {



        uint256 _rID = rID_ + 1;



        round_[_rID].pot = round_[_rID].pot.add(msg.value);

        emit F3Devents.onPotSwapDeposit(_rID, msg.value);

    }





    function distributeInternal(uint256 _rID, uint256 _pID, uint256 _eth, uint256 _team, uint256 _keys, F3Ddatasets.EventReturns memory _eventData_)

    private

    returns(F3Ddatasets.EventReturns)

    {



        uint256 _gen = (_eth.mul(fees_[_team].gen)) / 100;





        uint256 _air = (_eth / 100);

        airDropPot_ = airDropPot_.add(_air);



        uint256 cut = (fees_[_team].marketing).add(13);

        _eth = _eth.sub(_eth.mul(cut) / 100);





        uint256 _pot = _eth.sub(_gen);







        uint256 _dust = updateMasks(_rID, _pID, _gen, _keys);

        if (_dust > 0) {

            _gen = _gen.sub(_dust);

        }





        round_[_rID].pot = _pot.add(_dust).add(round_[_rID].pot);





        _eventData_.genAmount = _gen.add(_eventData_.genAmount);

        _eventData_.potAmount = _pot;



        return(_eventData_);

    }





    function updateMasks(uint256 _rID, uint256 _pID, uint256 _gen, uint256 _keys)

    private

    returns(uint256)

    {







        uint256 _ppt = (_gen.mul(1000000000000000000)) / (round_[_rID].keys);

        round_[_rID].mask = _ppt.add(round_[_rID].mask);







        uint256 _pearn = (_ppt.mul(_keys)) / (1000000000000000000);

        plyrRnds_[_pID][_rID].mask = (((round_[_rID].mask.mul(_keys)) / (1000000000000000000)).sub(_pearn)).add(plyrRnds_[_pID][_rID].mask);





        return(_gen.sub((_ppt.mul(round_[_rID].keys)) / (1000000000000000000)));

    }





    function withdrawEarnings(uint256 _pID)

    private

    returns(uint256)

    {



        updateGenVault(_pID, plyr_[_pID].lrnd);





        uint256 _earnings = (plyr_[_pID].win).add(plyr_[_pID].gen).add(plyr_[_pID].aff);

        if (_earnings > 0)

        {

            plyr_[_pID].win = 0;

            plyr_[_pID].gen = 0;

            plyr_[_pID].aff = 0;

        }



        return(_earnings);

    }





    function endTx(uint256 _pID, uint256 _team, uint256 _eth, uint256 _keys, F3Ddatasets.EventReturns memory _eventData_)

    private

    {

        _eventData_.compressedData = _eventData_.compressedData + (now * 1000000000000000000) + (_team * 100000000000000000000000000000);

        _eventData_.compressedIDs = _eventData_.compressedIDs + _pID + (rID_ * 10000000000000000000000000000000000000000000000000000);



        emit F3Devents.onEndTx

        (

            _eventData_.compressedData,

            _eventData_.compressedIDs,

            plyr_[_pID].name,

            msg.sender,

            _eth,

            _keys,

            _eventData_.winnerAddr,

            _eventData_.winnerName,

            _eventData_.amountWon,

            _eventData_.newPot,

            _eventData_.mktAmount,



            _eventData_.genAmount,

            _eventData_.potAmount,

            airDropPot_

        );

    }











    bool public activated_ = false;

    function activate()

    public onlyOwner {









        require(activated_ == false, "fomo3d already activated");





        activated_ = true;





        rID_ = 1;

        round_[1].strt = now;

        round_[1].end = now + rndInit_;

    }

}

