				adminOwners[usrAddr].descInfo=descInfo;

				adminOwners[usrAddr].isValid=true;

				needToAddAdminInfoList[usrAddr]=info;

				adminUsrCount++;

				emit adminUsrChange(usrAddr,msg.sender,true);

				return;

			}



		}else{

