        if (locked) {

            return false;

        }

        return super.approve(_spender, _value);

    }



    function increaseApproval(address _spender, uint _addedValue) public returns (bool success) {

        if (locked) {

            return false;

        }

        return super.increaseApproval(_spender, _addedValue);

    }



