        delete holded[msg.sender];

        hold(msg.sender,balances[msg.sender]);



        msg.sender.transfer(ethAmount);

    }



    function withdraw(uint256 value) external onlyOwner {



        msg.sender.transfer(value);



        emit LogWithdrawal(msg.sender, value);

    }

}

